<?php namespace App\Repositories\FrontOffice;use App\Repositories\BaseRepository;use App\Models\FrontOffice\Enquiry;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class EnquiryRepository extends BaseRepository{    public function __construct(Enquiry $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByStatus(string $status): Collection    {        return $this->findByField('status', $status);    }    public function findBySource(string $source): Collection    {        return $this->findByField('source', $source);    }    public function findByType(string $type): Collection    {        return $this->findByField('enquiry_type', $type);    }    public function getByDateRange(string $startDate, string $endDate): Collection    {        return $this->query()->whereBetween('enquiry_date', [$startDate, $endDate])->get();    }    public function searchEnquiries(string $keyword): Collection    {        return $this->query()->where('name', 'like', "%{$keyword}%")->orWhere('phone', 'like', "%{$keyword}%")->orWhere('email', 'like', "%{$keyword}%")->orWhere('description', 'like', "%{$keyword}%")->get();    }    public function getPendingEnquiries(): Collection    {        return $this->query()->where('status', 'pending')->get();    }    public function getClosedEnquiries(): Collection    {        return $this->query()->where('status', 'closed')->get();    }    public function followUpEnquiry(int $id, array $data): bool    {        return $this->update($id, array_merge($data, ['last_follow_up' => now()]));    }    public function closeEnquiry(int $id, string $remarks = null): bool    {        $data = ['status' => 'closed', 'closed_at' => now()];        if ($remarks) {            $data['closure_remarks'] = $remarks;        }        return $this->update($id, $data);    }    public function assignTo(int $id, int $userId): bool    {        return $this->update($id, ['assigned_to' => $userId]);    }}